class MKAverage:

    def __init__(self, m: int, k: int):
        self.m = m
        self.k = k
        self.nums = []

    def addElement(self, num: int) -> None:
        self.nums.append(num)
        self.nums.sort()

    def calculateMKAverage(self) -> int:
        if len(self.nums) < self.m:
            return -1
        else:
            return sum(self.nums[self.k:self.m-self.k]) // (self.m - 2*self.k)
```
